import string

def brute_force_caesar(msg):
    alpha = string.ascii_uppercase
    msg = msg.upper()
    for key in range(26):
        shifted = alpha[key:] + alpha[:key]
        trans = str.maketrans(alpha, shifted)
        print(f"Key #{key}: {msg.translate(trans)}")

if __name__ == "__main__":
    brute_force_caesar("TMDETUX")
